Bash(cd "C:/Users/timsc/Dropbox/GitHub/maine-town-quiz" && node -e "
const fs = require\('fs'\);
const orig = JSON.parse\(fs.readFileSync\('cumberland.geojson', 'utf8'\)\);
const simp = JSON.parse\(fs.readFileSync\('cumberland_5pct.geojson', 'utf8'\)\);
console.log\('ORIGINAL geometry type:', orig.features[0].geometry.type\);
console.log\('SIMPLIFIED geometry type:', simp.features[0].geometry.type\);

// Check for null geometries in simplified file
const nullGeoms = simp.features.filter\(f => !f.geometry || !f.geometry.coordinates\);
console.log\('Null geometries in simplified:', nullGeoms.length\);

// Check how many pass the filter
const filter = f => {
  const name = \(f.properties.TOWN || ''\).trim\(\);
  if \(!name\) return false;
  const u = name.toUpperCase\(\);
  if \(/UNORG|WELS|PATENT/.test\(u\)\) return false;
  if \(/ TWP\\$| TWP | TOWNSHIP| PLT\\$| PLT | PLANTATION|GRANT TWP|GRANT\\$/.test\(u\)\) return false;
  if \(/^T[A-Z0-9]+ R[A-Z0-9]+/.test\(u\)\) return false;
  return true;
};
console.log\('Original features after filter:', orig.features.filter\(filter\).length\);
console.log\('Simplified features after filter:', simp.features.filter\(filter\).length\);
")

